insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'By selling an article for ₹720, a man incurs a 20% loss. At what price should he sell it to gain 10%?', '₹720 में बेचने पर एक व्यक्ति को 20% loss होता है। 10% gain पाने के लिए उसे किस कीमत पर बेचना चाहिए?', 'Recover CP: CP = 720/0.80 = ₹900. Target SP = CP × 1.10 = 990.', 'Both the current loss and the target gain are expressed against CP. Recover CP from the loss SP (SP_loss = CP × (1 − 0.20)), then apply the gain multiplier (1 + 0.10) to get the target SP. Trying to jump from SP_loss directly to SP_target using a +30% (20+10) shift is always wrong because the bases are different.', 'CP = 720/0.80 = ₹900। Target SP = CP × 1.10 = 990।', 'Current loss और target gain दोनों CP पर। पहले CP निकालें (720/0.80=900), फिर gain factor (1.10) लगाकर target SP। SP_loss से सीधे +30% नहीं।', 'MEDIUM', array['profit-loss','target-sp','reverse-calculation','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹990', '₹990', true, null, null);
