insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹900', '₹900', false, 'This is the CP (720/0.80). The target SP is CP × 1.10 = 990.', 'यह CP (720/0.80) है। Target SP = CP × 1.10 = 990।');
