insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'A trader gains 25% on the cost price of an article. What is his gain as a percentage of the selling price?', 'एक व्यापारी CP पर 25% gain लेता है। SP के percent में उसका gain कितना है?', 'Take CP = 100. SP = 125. Gain = 25. As % of SP: 25/125 × 100 = 20%.', 'Gain on cost (markup) and gain on sales (margin) give different percent values. Markup = gain/CP; margin = gain/SP. They only coincide when gain = 0. The formula to convert: margin = markup/(1 + markup) when markup is in fractional form.', 'CP = 100 मानें। SP = 125। Gain = 25। SP के percent में: 25/125 × 100 = 20%।', 'Gain-on-cost (markup) और gain-on-sales (margin) अलग-अलग percent देते हैं। Conversion: margin = markup/(1 + markup) (fractional markup में)।', 'MEDIUM', array['profit-loss','percent-base-switch','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '25%', '25%', false, 'Assumed gain% is base-invariant — reported the markup (25%) as the margin. But switching denominator from CP to SP changes the value.', 'Gain% को base-independent माना — markup (25%) को margin के रूप में दे दिया। CP से SP में denominator बदलने पर answer बदलता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '20%', '20%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '16.67%', '16.67%', false, 'Used 25/150 — added gain 25 to SP 125 to form 150 as denominator (double-counted the gain): 25/150 = 16.67%.', 'Denominator में gain को दोबारा जोड़ा: 25/(125+25) = 25/150 = 16.67%।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '12.5%', '12.5%', false, 'Halved the markup 25% → 12.5% (used division by 2 as the markup-to-margin converter). Correct converter: markup/(1 + markup) = 0.25/1.25 = 0.20.', 'Markup 25% को आधा करके 12.5% किया (mistakenly division by 2 को converter समझा)। सही converter: markup/(1 + markup) = 0.25/1.25 = 0.20।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'The marked price of a TV is 25% above its cost price. A discount of 12% is offered on the MP. Find the profit percentage.', 'एक TV का marked price CP से 25% अधिक है। MP पर 12% discount मिलता है। profit% क्या है?', 'CP = 100 ⇒ MP = 125. SP = 125 × 0.88 = 110. Profit% = 10%. Shortcut: net = m + d − md/100 with m=+25, d=−12, giving 10%.', 'Markup above CP produces MP; discount below MP produces SP. Net profit over CP = (1 + m)(1 − d) − 1. Concretely: 1.25 × 0.88 − 1 = 0.10 = 10%. Treating markup and discount as the same-base subtraction is the most common exam error.', 'CP = 100 ⇒ MP = 125। SP = 125 × 0.88 = 110। Profit% = 10%।', 'Markup CP के ऊपर, discount MP पर। net profit = (1+m)(1−d) − 1 = 1.25 × 0.88 − 1 = 10%।', 'MEDIUM', array['profit-loss','markup','discount','successive-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '10%', '10%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '13%', '13%', false, 'Subtracted 25 − 12 directly — doesn''t work when bases differ (markup on CP, discount on MP).', '25−12 सीधे निकाला — pr bases अलग हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '15%', '15%', false, 'Tried 25 − (12% of 25) = 22 — close logic but wrong formulation.', '25 − (12% of 25) = 22 जैसा लगाया — तरीका सही नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '12%', '12%', false, 'Used the discount percent as profit percent — these are unrelated.', 'discount% को profit% मान लिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 3, 'A man buys an article and sells it at a 10% gain. If he had bought it for ₹50 less and sold for ₹30 less, he would have gained 20%. Find the original cost price.', 'एक आदमी एक article खरीदकर 10% gain पर बेचता है। अगर वह उसे ₹50 कम में खरीदता और ₹30 कम में बेचता, तो 20% gain होता। original CP क्या है?', 'Let CP = x. Original SP = 1.10x. New CP = x − 50, new SP = 1.10x − 30. New gain condition: 1.10x − 30 = 1.20(x − 50) ⇒ 1.10x − 30 = 1.20x − 60 ⇒ 30 = 0.10x ⇒ x = ₹300.', 'Translate the two gain conditions into two equations, subtract to eliminate the unknown SP. This yields one equation in CP. Careful with sign consistency when moving terms across the equality.', 'CP = x। Original SP = 1.10x। नई SP = 1.10x − 30 = 1.20 × (x − 50) → 1.10x − 30 = 1.20x − 60 → x = 300।', 'दोनों gain conditions को equations में बदलें, घटाकर SP eliminate करें। एक unknown (CP) बचता है।', 'MEDIUM', array['profit-loss','equation-setup','word-problem','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹200', '₹200', false, 'Doesn''t satisfy the second condition: with CP 200, new SP would be 190, but 1.20×(200−50) = 180 ≠ 190.', 'CP 200 पर second condition fail: new SP 190, पर 1.20×(200−50) = 180 ≠ 190।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹250', '₹250', false, 'Equation test: new SP = 1.10×250 − 30 = 245, 1.20×(250−50) = 240 ≠ 245.', '250 पर check: 1.10×250 − 30 = 245, पर 1.20×200 = 240 ≠ 245।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹300', '₹300', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹225', '₹225', false, 'Algebra slip — try the system: 1.10x − 30 = 1.20(x − 50) gives x = 300, not 225.', 'Algebra में गलती — 1.10x − 30 = 1.20(x − 50) से x = 300।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 4, 'A shopkeeper allows a ''Buy 3 Get 1 Free'' offer. What is the effective discount percentage?', 'एक दुकानदार ''Buy 3 Get 1 Free'' का offer देता है। effective discount% क्या है?', 'Customer pays for 3 items but takes 4. Effective price per item = (3/4) of marked. Discount = 1/4 = 25%.', 'Bulk ''get one free'' offers are framed as ''free per paid'' (which suggests 1/3 ≈ 33%) but the exam asks for discount percent on the total items taken: out of 4 items the customer pays for 3, so 1/4 is the effective savings. Wording sensitivity matters.', 'Customer 3 items की payment करता है, 4 ले जाता है। Per-item effective price = (3/4) MP। Discount = 1/4 = 25%।', '''Free per paid'' framing 1/3 (≈33%) सुझाती है, पर exam ''total taken'' पर discount पूछता है: 4 में से 3 की payment → 1/4 bachat।', 'MEDIUM', array['profit-loss','discount','bulk-offer','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '33.33%', '33.33%', false, 'Computed 1/3 = 33.33%: used ''free items per PAID item'' (1 free per 3 paid). The discount uses ''free items per TOTAL taken'' (1 of 4).', '1/3 = 33.33% निकाला: ''per paid item'' (1 free per 3 paid) framing लगाई। Discount ''per total taken'' (1 of 4) पर होता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '25%', '25%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '20%', '20%', false, 'Miscounted: treated the offer as ''Buy 4 Get 1 Free'' (1/5 = 20%) instead of ''Buy 3 Get 1 Free'' (1/4 = 25%).', 'Offer को ''Buy 4 Get 1 Free'' (1/5 = 20%) समझा, जबकि है ''Buy 3 Get 1 Free'' (1/4 = 25%)।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '50%', '50%', false, 'Read the offer as ''Buy 1 Get 1 Free'' (1/2 = 50%). Actual offer gives 1 free per 4 total, not 1 per 2.', 'Offer को ''Buy 1 Get 1 Free'' (1/2 = 50%) पढ़ा। Actual में 4 में से 1 free, 2 में से 1 नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 5, 'A shopkeeper prices goods at CP (marked price = CP), offers a 10% discount, and also delivers 20% less weight than stated. Find his overall gain or loss percentage.', 'एक दुकानदार goods को CP पर mark करता है (MP = CP), फिर 10% discount देता है, और stated से 20% कम weight देता है। overall gain/loss% क्या है?', 'Let CP per true unit = ₹100, MP = ₹100. After 10% discount, customer pays ₹90. But he receives only 0.80 true units. So the shop''s revenue for 0.80 true units = ₹90. Shop''s cost for those 0.80 true units = 0.80 × 100 = ₹80. Gain = 90 − 80 = ₹10 on cost ₹80 ⇒ gain% = 10/80 × 100 = 12.5%.', 'When discount (a loss-mechanism) and short-weight (a gain-mechanism) combine, the correct frame is ''same quantity of goods on both sides''. Compute what the shop charges for a delivered unit and what it costs them — the gap, divided by their actual cost, is the gain%. Mixing percentages directly double-counts bases.', 'मान लें CP per true unit = ₹100, MP = ₹100। 10% discount के बाद customer ₹90 देता है। पर receive 0.80 units ही करता है। Shop का cost 0.80 units के लिए = 0.80 × 100 = ₹80। Revenue ₹90। Gain = 10 on cost 80 ⇒ 10/80 × 100 = 12.5%।', 'Discount (loss-मanism) और short-weight (gain-mानism) combine हों तो same-quantity-of-goods frame लें: delivered unit पर shop की revenue और cost दोनों निकालें, gap को actual cost पर percent में बदलें।', 'HARD', array['profit-loss','discount','dishonest-merchant','combined','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Loss 10%', 'Loss 10%', false, 'Only counted the discount effect; ignored the short-weight uplift.', 'सिर्फ discount लगाया; short-weight uplift छोड़ दिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Gain 12.5%', 'Gain 12.5%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Gain 10%', 'Gain 10%', false, 'Only counted the short-weight uplift (100/80 = +25% gain on delivered) without netting the 10% discount.', 'सिर्फ short-weight का uplift लिया; 10% discount का loss-effect नहीं netted किया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Gain 25%', 'Gain 25%', false, 'Jumped to 1/0.80 − 1 = 25% ignoring the 10% discount entirely.', '1/0.80 − 1 = 25% लगा दिया; 10% discount पूरा नज़रअंदाज़।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 6, 'Three-fourths of a shipment is sold at a 20% gain. At what gain or loss percentage should the remaining one-fourth be sold so that the overall transaction breaks even?', 'एक shipment का 3/4 हिस्सा 20% gain पर बिकता है। शेष 1/4 को किस gain/loss% पर बेचा जाए ताकि overall transaction पर कोई gain/loss न हो (break-even)?', 'Let total CP = 100 (unit cost = 1). First 3/4 earns 3/4 × 1 × 0.20 = 0.15 gain. For break-even, remaining 1/4 must bear a loss equal to 0.15 in absolute terms. Loss on 1/4 of cost 0.25 ⇒ loss% = 0.15/0.25 = 60%.', 'To break even, absolute gain equals absolute loss, not percent gain equals percent loss. Because the gaining and losing pools have different CP sizes (3:1), the smaller pool must bear a proportionally larger percent loss. The ratio of percent-loss to percent-gain equals the ratio of the larger pool to the smaller (3:1 here).', 'Total CP = 100 (unit cost = 1) मानें। पहला 3/4 पर gain = 0.15। Break-even के लिए बाकी 1/4 पर loss = 0.15 absolute। Loss% = 0.15/0.25 = 60%।', 'Break-even के लिए absolute gain = absolute loss (percent नहीं)। Pools का size अलग होने पर small pool को बड़ा percent loss झेलना पड़ता है। ratio = large pool/small pool = 3:1।', 'HARD', array['profit-loss','partial-sale','break-even','weighted-percentage','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20% loss', '20% loss', false, 'Assumed symmetric loss equal to the gain — but the bases (quantities) differ.', 'Symmetric loss माना; पर quantities अलग हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '40% loss', '40% loss', false, 'Doubled the loss percent to compensate the 3× quantity — close idea but wrong direction of compensation: 60% loss is right.', 'compensation 3× quantity के लिए doubled; सही 3×20% = 60% loss।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '60% loss', '60% loss', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '80% loss', '80% loss', false, 'Overshot — only 3× the gain rate is needed, i.e., 60%.', 'ज़्यादा; 3× gain rate = 60% चाहिए।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 7, 'An article is sold at a 10% loss. If it had been sold for ₹132 more, the transaction would have yielded a 12% gain. Find the cost price.', 'एक article 10% loss पर बिका। अगर ₹132 अधिक में बेचा जाता, तो 12% gain होता। CP क्या है?', 'SP_high − SP_low = (1.12 − 0.90) × CP = 0.22 × CP = 132 ⇒ CP = 600.', 'The gap between two SPs expressed on the same CP equals the difference of their multipliers times CP. The gain percent (+12) and the loss percent (−10) translate to multipliers 1.12 and 0.90; their difference (0.22) times CP gives the price gap.', 'SP_high − SP_low = (1.12 − 0.90) × CP = 0.22 × CP = 132 → CP = 600।', 'दो SPs का gap (same CP पर) = (उनके multipliers का अंतर) × CP। यहाँ 0.22 × CP = 132।', 'HARD', array['profit-loss','sp-difference','equation-setup','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹600', '₹600', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹660', '₹660', false, 'Added gain 10% of 600 = 60 to 600 → 660. Reported a post-gain SP rather than solving the gap equation 0.22x = 132.', '600 में gain 10% = 60 जोड़कर 660 दिया: post-gain SP दे दिया, जबकि gap equation 0.22x = 132 हल करना था।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹550', '₹550', false, 'Divided 132 by 0.24: used sum of rates (0.12 + 0.12 or similar) instead of their difference. Correct denominator is (0.12 − (−0.10)) = 0.22.', '132 को 0.24 से भाग दिया: rates का sum लगाया, difference नहीं। सही denominator = 0.12 − (−0.10) = 0.22।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹1320', '₹1320', false, 'Multiplied 132 × 10 (treated 10% as the factor, skipping the × 100 step): 132 × 10 = 1320. Correct is 132/0.22 = 600.', '132 × 10 लगाया (10% को factor समझा, × 100 step छोड़ दिया): 132 × 10 = 1320। सही 132/0.22 = 600।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 8, 'A shopkeeper purchases 21 items for ₹1,050. He sells some at a 25% gain and the rest at a 10% loss, netting an overall 10% gain on the whole lot. How many items were sold at a gain?', 'एक दुकानदार ₹1,050 में 21 items खरीदता है। कुछ items 25% gain पर और बाकी 10% loss पर बिकती हैं, पूरे lot पर overall 10% gain होता है। कितनी items gain पर बिकीं?', 'Per-item CP = 1050/21 = ₹50. Alligation: distance from target (+10%) to gain arm (+25%) = 15; to loss arm (−10%) = 20. Quantity ratio gain:loss = 20:15 = 4:3. Gain pool = 4/(4+3) × 21 = 12. Verify: 12 × 50 × 0.25 − 9 × 50 × 0.10 = 150 − 45 = 105 = 10% × 1050. ✓', 'Alligation places the two ''arms'' (+25%, −10%) on a number line with the target (+10%) between them, computes signed distances, and inverts the ratio to get the quantity split. Items were chosen so the 4:3 ratio maps to whole numbers 12:9 summing to 21 — no rounding.', 'Per-item CP = 1050/21 = ₹50। Alligation: target (+10%) से gain arm (+25%) तक दूरी = 15; loss arm (−10%) तक दूरी = 20। Quantity ratio gain:loss = 20:15 = 4:3। Gain pool = 4/7 × 21 = 12। Verify: 12 × 50 × 0.25 − 9 × 50 × 0.10 = 150 − 45 = 105 = 10% × 1050। ✓', 'Alligation में दो arms (+25%, −10%) को number line पर रखें, target (+10%) बीच में, signed दूरियाँ निकालें, ratio invert करके quantity split। यहाँ 4:3 ratio को 12:9 (sum 21) whole numbers पर map किया — कोई rounding नहीं।', 'HARD', array['profit-loss','alligation','partial-sale','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '9', '9', false, 'Applied alligation but assigned the arm distances to the wrong pools: took 20/35 × 21 = 12 as the LOSS count and reported 9 as the gain count. Actual alligation gives 12:9 with gain = 12.', 'Alligation में arms उलट दिए: 20/35 × 21 = 12 को loss count मान लिया और gain count 9 दे दिया। सही 12:9 में gain = 12।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '12', '12', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '15', '15', false, 'Used ratio 5:2 instead of 4:3 (misread arm distances as 25 and 10 instead of 20 and 15): 5/7 × 21 = 15.', '4:3 की जगह 5:2 ratio लगाया (arm distances 25 और 10 पढ़ लिए, सही 20 और 15 हैं): 5/7 × 21 = 15।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '10', '10', false, 'Halved the total 21 (round half-split to 10 + 11) assuming the target 10% sits midway between +25 and −10. Alligation gives an asymmetric 12:9 split.', 'Target 10% को +25 और −10 के बीच mid मानकर total 21 को आधा (10 + 11) कर दिया। सही alligation से 12:9 asymmetric split मिलता है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 9, 'A dealer sells 8 articles at the marked price of 10 articles. Find the discount percentage.', 'एक dealer 10 articles के marked price पर 8 articles बेचता है। discount% क्या है?', 'Customer pays the price of 10 but receives only 8. Discount = 2 missing articles out of 10 marked = 2/10 = 20%.', 'The discount reference is the marked quantity (what the customer would have expected at the marked price), not the received quantity. ''X articles for the price of Y'' (with X < Y) → discount = (Y − X)/Y.', 'Customer 10 की payment करता है, पाता 8। Discount = 2/10 = 20%।', '''X articles for the price of Y'' (X < Y) में discount base marked quantity Y होती है, delivered quantity X नहीं। Discount = (Y − X)/Y।', 'HARD', array['profit-loss','discount','per-unit-pricing','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20%', '20%', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '25%', '25%', false, 'Used 2/8 (inverted: extra articles per paid articles) instead of 2/10 (fewer articles per marked quantity).', '2/8 लगाया (paid पर); सही 2/10 (marked पर)।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '12.5%', '12.5%', false, 'Used 1/8 — wrong numerator (off by one from 2).', '1/8 लगाया; numerator गलत।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '16.66%', '16.66%', false, 'Used 2/12 — denominator invented.', '2/12 लगाया; denominator बना दिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 10, 'If A : B = 2 : 3 and A = 12, find B.', 'यदि A : B = 2 : 3 और A = 12 हो, तो B निकालिए।', 'A:B = 2:3 ⇒ B = A × 3/2 = 12 × 3/2 = 18.', 'A ratio a:b defines a common scale factor k such that A = ak and B = bk. Given A, solve for k = A/a, then B = k × b. Alternately, B = A × (b/a) — the ratio of the B-part to the A-part.', 'A:B = 2:3 ⇒ B = A × 3/2 = 12 × 3/2 = 18।', 'अनुपात a:b एक common scale factor k बताता है जहाँ A = ak, B = bk। A से k = A/a निकालें, फिर B = k × b। या सीधे B = A × (b/a)।', 'EASY', array['ratio-proportion','direct-ratio','basic','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '18', '18', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '8', '8', false, 'Inverted the ratio: computed 12 × 2/3 = 8. The ratio A:B = 2:3 means B = A × 3/2, not A × 2/3.', 'Ratio उल्टा लगाया: 12 × 2/3 = 8 निकाला। A:B = 2:3 का मतलब B = A × 3/2 है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '15', '15', false, 'Added the ratio parts as units: 12 + 3 = 15. Ratios scale multiplicatively, not additively.', 'Ratio parts जोड़ दिए: 12 + 3 = 15। Ratios multiplicatively scale होते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '36', '36', false, 'Multiplied A by the sum of ratio parts: 12 × 3 = 36. Correct formula uses only the B-part (3/2).', 'A को 3 से गुणा किया: 12 × 3 = 36। सही formula: B = A × 3/2।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 11, 'Divide ₹600 between P and Q in the ratio 5 : 3. How much does P get?', '₹600 को P और Q के बीच 5 : 3 के अनुपात में बाँटिए। P को कितना मिलेगा?', 'P''s share = 600 × 5/(5+3) = 600 × 5/8 = 375.', 'When a total is split in ratio a:b, person A gets (a/(a+b)) × total. The sum of ratio parts is the denominator; it represents ''one full unit'' of the total. Forgetting to sum ratio parts in the denominator is the most common slip.', 'P का share = 600 × 5/(5+3) = 600 × 5/8 = 375।', 'Total को a:b में बाँटें तो A को (a/(a+b)) × total मिलता है। Ratio parts का sum denominator में — यह ''one full unit'' है। Sum भूलना common गलती है।', 'EASY', array['ratio-proportion','partition','basic','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹375', '₹375', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹225', '₹225', false, 'Gave Q''s share (₹600 × 3/8 = 225) as P''s share. Swapped the ratio parts.', 'Q का share (600 × 3/8 = 225) को P का share मान लिया। Ratio parts swap हो गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹300', '₹300', false, 'Divided the total by 2 (assumed equal split): 600/2 = 300. The ratio 5:3 is not equal.', 'Total को 2 से भाग दिया (equal split मान लिया): 600/2 = 300। 5:3 equal नहीं है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹500', '₹500', false, 'Used 5 of 6 (5/(5+1)) instead of 5/(5+3): 600 × 5/6 = 500. Summed ratio parts wrong.', 'Ratio parts का sum गलत: 600 × 5/6 = 500 लगाया, सही 5/(5+3) = 5/8।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 12, 'The ratio of boys to girls in a class is 3:2. If there are 15 boys, how many students are in the class in total?', 'एक कक्षा में लड़कों और लड़कियों का अनुपात 3:2 है। यदि 15 लड़के हों, तो कक्षा में कुल कितने छात्र हैं?', 'Scale factor k = 15/3 = 5. Girls = 2k = 10. Total = 15 + 10 = 25.', 'From any one part, recover the scale factor k = (given part)/(its ratio piece). All other parts are multiples of k. The total is k × (sum of all ratio pieces).', 'Scale factor k = 15/3 = 5। Girls = 2k = 10। Total = 15 + 10 = 25।', 'किसी एक part से scale factor k = (दिया हुआ part)/(उसका ratio piece) निकालें। बाकी parts k के multiples। Total = k × (सभी pieces का sum)।', 'EASY', array['ratio-proportion','part-to-whole','basic','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '25', '25', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '10', '10', false, 'Reported only the girls count (15 × 2/3 = 10) as total. Total includes both boys and girls.', 'केवल लड़कियों की संख्या (15 × 2/3 = 10) को total दे दिया। Total = लड़के + लड़कियाँ।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '45', '45', false, 'Multiplied boys by sum of ratio (15 × 3 = 45). Scale factor should be found first: k = 15/3 = 5, then total = k × (3+2) = 25.', 'Boys × ratio sum (15 × 3 = 45) लगाया। पहले k = 15/3 = 5, फिर total = k × (3+2) = 25।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '30', '30', false, 'Doubled the boys count (15 × 2 = 30) assuming 2:1 boys:girls. Ratio is 3:2, not 2:1.', 'Boys × 2 = 30 लगाया (ratio 2:1 मानकर)। असली ratio 3:2 है, 2:1 नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 13, 'If a : b = 3 : 4 and b : c = 2 : 5, find a : c.', 'यदि a : b = 3 : 4 और b : c = 2 : 5, तो a : c ज्ञात कीजिए।', 'Make b common. a:b = 3:4 and b:c = 2:5 = 4:10 (multiply by 2 to make b=4). So a:b:c = 3:4:10 ⇒ a:c = 3:10.', 'To chain two ratios that share a middle term, scale them so the middle term matches. Once they share the same middle value, you can read a:c (or any pair) directly from the combined chain.', 'b को common बनाएँ। a:b = 3:4 और b:c = 2:5 = 4:10 (× 2 से b = 4)। अतः a:b:c = 3:4:10 ⇒ a:c = 3:10।', 'दो ratios में common middle term scale करके match करें। एक बार middle बराबर हो जाए तो chained ratio से a:c (या कोई भी pair) सीधे पढ़ लें।', 'EASY', array['ratio-proportion','chained-ratio','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '3 : 10', '3 : 10', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '3 : 5', '3 : 5', false, 'Reported the second ratio''s c-part (5) with the first ratio''s a-part (3), ignoring that b differs between the two ratios (4 vs 2). Scale b to a common value.', 'दूसरी ratio का c (5) और पहली ratio का a (3) सीधे लिए — दोनों ratios में b अलग (4 vs 2) है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '6 : 5', '6 : 5', false, 'Multiplied the first ratio''s 3 by 2 (= 6) but left c unchanged at 5. Should also scale c by the same factor that makes b common.', 'पहली ratio के 3 को × 2 = 6 किया पर c को 5 रखा। b को common बनाने के factor से c को भी scale करना था।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '3 : 20', '3 : 20', false, 'Multiplied the c-part (5) by the b-part of the second ratio (4) to ''scale'': 5 × 4 = 20. Correct scaling makes b common, not c.', 'c (5) को दूसरी ratio के b (4) से गुणा किया: 5 × 4 = 20। Scaling b पर होती है, c पर नहीं।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 14, 'If 4 : x :: x : 9, find the positive value of x.', 'यदि 4 : x :: x : 9 हो, तो x का धनात्मक मान निकालिए।', 'a:x :: x:b ⇒ x² = a × b = 4 × 9 = 36 ⇒ x = 6 (positive root).', 'In a proportion a:x :: x:b (x is called the ''mean proportion''), the product of extremes equals the product of means: a × b = x × x. So x is the geometric mean of a and b — always less than or equal to the arithmetic mean (equal only when a = b).', 'a:x :: x:b ⇒ x² = a × b = 4 × 9 = 36 ⇒ x = 6 (positive)।', 'Proportion a:x :: x:b में (x mean proportion है), extremes का product = means का product: a × b = x²। x, a और b का geometric mean होता है (arithmetic mean से छोटा या बराबर)।', 'EASY', array['ratio-proportion','mean-proportion','basic','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '6', '6', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '36', '36', false, 'Gave x² = 36 as x itself, skipping the square root. Mean proportion x = √(4 × 9), not 4 × 9.', 'x² = 36 को ही x मान लिया — square root लेना भूल गए। Mean proportion x = √(4 × 9) है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '13', '13', false, 'Added the two terms: 4 + 9 = 13. Mean proportion is the geometric mean (√ab), not the sum.', 'दोनों terms जोड़े: 4 + 9 = 13। Mean proportion geometric mean (√ab) है, sum नहीं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '6.5', '6.5', false, 'Computed the arithmetic mean (4 + 9)/2 = 6.5. For proportions, the mean term uses geometric mean (√ab), not arithmetic.', 'Arithmetic mean (4 + 9)/2 = 6.5 लगाया। Proportions में mean term geometric mean होती है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 15, 'A sum of ₹1,400 is divided among A, B, and C in the ratio 2 : 3 : 2. Find C''s share.', '₹1,400 को A, B, C में 2 : 3 : 2 के अनुपात में बाँटा गया। C का share क्या है?', 'C''s share = 1400 × 2/(2+3+2) = 1400 × 2/7 = 400.', 'For a three-way split in ratio a:b:c, each share is (its part)/(a+b+c) × total. The sum in the denominator is always ''everyone combined'', even when two parts are equal.', 'C का share = 1400 × 2/(2+3+2) = 1400 × 2/7 = 400।', 'तीन-भाग split a:b:c में हर share = (own part)/(a+b+c) × total। Denominator सब parts का sum होता है, भले ही दो parts बराबर हों।', 'EASY', array['ratio-proportion','partition','three-way-split','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹400', '₹400', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹600', '₹600', false, 'Gave B''s share (1400 × 3/7 = 600) as C''s share — read the middle ratio piece.', 'B का share (1400 × 3/7 = 600) को C का share मान लिया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹350', '₹350', false, 'Divided total by 4 (treating two 2-parts and one 3-part as ''4 equal slots''): 1400/4 = 350. Ratio parts aren''t equal slots.', 'Total को 4 से भाग दिया (दो 2-parts और एक 3-part को ''4 equal slots'' मान लिया): 1400/4 = 350।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹500', '₹500', false, 'Halved C''s portion''s ratio piece (2/4 instead of 2/7) — used wrong denominator: 1400 × 2/4 = 700 or 1400 × 2/5 = 560, then adjusted. Correct denom = 2+3+2 = 7.', 'C के लिए wrong denominator: 2/4 या 2/5 लगाया। सही 2/(2+3+2) = 2/7।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 16, 'The present ages of A and B are in the ratio 5 : 4. After 6 years, their ages will be in the ratio 11 : 9. Find B''s present age.', 'A और B की वर्तमान ages का ratio 5 : 4 है। 6 साल बाद यह 11 : 9 हो जाएगा। B की वर्तमान age क्या है?', 'Let A = 5k, B = 4k. After 6 years: (5k + 6)/(4k + 6) = 11/9. Cross-multiply: 9(5k + 6) = 11(4k + 6) ⇒ 45k + 54 = 44k + 66 ⇒ k = 12. B = 4k = 48.', 'Let scale k satisfy A = 5k, B = 4k. The future-ratio equation becomes linear in k after cross-multiplying. Solve for k, then multiply to get B.', 'A = 5k, B = 4k मानें। 6 साल बाद (5k + 6)/(4k + 6) = 11/9 ⇒ 9(5k + 6) = 11(4k + 6) ⇒ k = 12। B = 4k = 48।', 'Scale k के साथ A = 5k, B = 4k। Future-ratio equation cross-multiplication के बाद k में linear बनता है। k निकालकर B = 4k।', 'MEDIUM', array['ratio-proportion','age-problem','two-equations','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '48 years', '48 साल', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '60 years', '60 साल', false, 'Gave A''s present age (5k = 60 with k = 12) as B''s. A is the 5-part; B is the 4-part.', 'A की present age (5k = 60, k = 12) को B''s age दे दी। A 5-part है, B 4-part।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '54 years', '54 साल', false, 'Gave B''s future age (4k + 6 = 54 with k = 12) instead of present. Question asks PRESENT age.', 'B की future age (4k + 6 = 54, k = 12) दी, present नहीं। Question PRESENT पूछ रहा है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '24 years', '24 साल', false, 'Used wrong scale k = 6 (instead of 12), giving B = 4 × 6 = 24. Cross-multiplication 9(5k+6) = 11(4k+6) gives k = 12, not 6.', 'गलत scale k = 6 (12 की जगह) से B = 4 × 6 = 24 निकाला। Cross-multiplication से k = 12।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 17, 'Two numbers are in the ratio 5 : 7. If 4 is added to each, the ratio becomes 3 : 4. Find the smaller number.', 'दो संख्याओं का ratio 5 : 7 है। दोनों में 4 जोड़ने पर ratio 3 : 4 हो जाता है। छोटी संख्या क्या है?', 'Let numbers = 5k, 7k. (5k + 4)/(7k + 4) = 3/4. Cross: 4(5k + 4) = 3(7k + 4) ⇒ 20k + 16 = 21k + 12 ⇒ k = 4. Smaller = 5 × 4 = 20.', 'When the same number is added to both parts of a ratio, the ratio generally changes (unless both original parts are equal, which violates the stated ratios). Parametrize by k, form the after-shift equation, solve the linear equation in k, then scale.', 'Numbers = 5k, 7k मानें। (5k + 4)/(7k + 4) = 3/4 ⇒ 4(5k + 4) = 3(7k + 4) ⇒ k = 4। Smaller = 5k = 20।', 'Ratio के दोनों parts में same number जोड़ने पर ratio बदलता है। k से parametrize करें, after-shift equation बनाएँ, linear equation solve।', 'MEDIUM', array['ratio-proportion','equation-setup','ratio-shift','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '20', '20', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '28', '28', false, 'Gave the larger number (7k = 28) instead of smaller. ''Smaller'' is the 5-part.', 'बड़ी संख्या (7k = 28) दे दी, छोटी नहीं। Smaller = 5-part।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '15', '15', false, 'Used k = 3 (mis-solved the linear equation), so 5k = 15. The right equation gives k = 4.', 'Linear equation गलत solve: k = 3 लगाया, 5k = 15। सही k = 4।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '24', '24', false, 'Added 4 to the correct answer 20 (returned the SHIFTED value). Question asks for the original smaller number, not after-shift.', 'सही answer 20 में 4 जोड़कर 24 दे दिया (shifted value)। Question original छोटी संख्या पूछ रहा है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 18, 'If the ratio of the present ages of a father and son is 7:2 and after 10 years it becomes 9:4, find the present age of the son.', 'पिता और पुत्र की वर्तमान ages का ratio 7:2 है; 10 साल बाद यह 9:4 हो जाएगा। पुत्र की वर्तमान age क्या है?', 'Let father = 7k, son = 2k. After 10 years: (7k + 10)/(2k + 10) = 9/4. Cross: 4(7k + 10) = 9(2k + 10) ⇒ 28k + 40 = 18k + 90 ⇒ 10k = 50 ⇒ k = 5. Son = 2k = 10.', 'Age ratio problems over time: parametrize both present ages by a common scale k, apply the future-ratio constraint, and solve the linear equation. The same +t offset applies to BOTH ages, preserving the time gap but usually changing the ratio.', 'Father = 7k, son = 2k मानें। 10 साल बाद (7k + 10)/(2k + 10) = 9/4 ⇒ 4(7k + 10) = 9(2k + 10) ⇒ 10k = 50 ⇒ k = 5। Son = 2k = 10।', 'Age-over-time ratio: दोनों present ages को k से parametrize करें, future-ratio लगाएँ, linear equation solve। +t offset दोनों पर लगता है।', 'MEDIUM', array['ratio-proportion','age-problem','two-equations','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '10 years', '10 साल', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '14 years', '14 साल', false, 'Used future-ratio son part (4) × 10/4 incorrectly: from 9:4, new son age = 4k = 4 × 5 = 20, subtract 10 gives 10 not 14. B came from a muddled middle step.', 'Future son 4k = 20, − 10 = 10 सही। B एक गलत intermediate से आया।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '20 years', '20 साल', false, 'Gave future age of son (present + 10 = 20) as present age. Question asks PRESENT.', 'Son की future age (present + 10 = 20) दी। Question PRESENT पूछ रहा है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '35 years', '35 साल', false, 'Gave father''s present age (7k = 35) instead of son''s. Father is 7-part, son is 2-part.', 'Father की present age (7k = 35) दे दी। Son 2-part है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 19, 'A and B invest ₹8,000 and ₹12,000 respectively in a business. At the end of the year, the profit is ₹3,000. Find A''s share.', 'A और B ने एक business में क्रमशः ₹8,000 और ₹12,000 invest किए। साल के अंत में profit ₹3,000 हुआ। A का share क्या है?', 'Investment ratio 8000:12000 = 2:3. A''s share = 3000 × 2/(2+3) = 3000 × 2/5 = 1200.', 'When investments are made for the same duration, profit splits in the ratio of investments alone. If durations differ, multiply each investment by its duration (the ''time-weighted investment'') and split the profit in those ratios.', 'Investment ratio 8000:12000 = 2:3। A का share = 3000 × 2/(2+3) = 3000 × 2/5 = 1200।', 'Same duration पर profit investments के ratio में बँटता है। अलग durations हो तो investment × time (time-weighted investment) के ratio में बँटाएँ।', 'MEDIUM', array['ratio-proportion','partnership','profit-split','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹1,200', '₹1,200', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹1,500', '₹1,500', false, 'Split profit equally: 3000/2 = 1500. Partnership profit splits in the RATIO of investments, not equally (unless investments are equal).', 'Profit equally बाँट दिया: 3000/2 = 1500। Partnership में profit investments के RATIO में बँटता है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹1,800', '₹1,800', false, 'Gave B''s share (3000 × 12/(8+12) = 3000 × 3/5 = 1800) instead of A''s. A has the smaller investment, so smaller share.', 'B का share (3000 × 12/20 = 1800) A को दे दिया। A की investment कम है, share भी कम।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹600', '₹600', false, 'Used 2/5 instead of 2/5 but of total 1500 mistakenly: 3000 × 8/20 = 1200, but student did 1500 × 8/20 = 600. Used profit/2 as base.', '3000 की जगह 1500 (आधा) को base मान लिया: 1500 × 8/20 = 600।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 20, 'A and B enter a partnership. A invests ₹10,000 for 12 months and B invests ₹15,000 for 8 months. Find the ratio of their profit shares.', 'A और B partnership में हैं। A ने ₹10,000 को 12 महीने और B ने ₹15,000 को 8 महीने invest किया। उनके profit shares का ratio निकालिए।', 'Time-weighted investments: A = 10000 × 12 = 120000; B = 15000 × 8 = 120000. Ratio = 120000 : 120000 = 1 : 1.', 'In a partnership with different investments AND different durations, profit shares are in the ratio of (investment × time), not just investment alone. Coincidentally equal products lead to a 1:1 split even when neither investment nor duration alone would suggest it.', 'Time-weighted: A = 10000 × 12 = 120000, B = 15000 × 8 = 120000। Ratio = 120000 : 120000 = 1 : 1।', 'अलग investments AND अलग durations वाले partnership में profit (investment × time) के ratio में। Coincidence से equal हों तो 1:1 भी निकल सकता है।', 'MEDIUM', array['ratio-proportion','partnership','time-weighted','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '1 : 1', '1 : 1', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '2 : 3', '2 : 3', false, 'Used only the investment ratio (10:15 = 2:3), ignoring the time durations (12 vs 8 months).', 'Investment ratio (10:15 = 2:3) ही लगाया — durations (12 vs 8 महीने) छोड़ दिए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '3 : 2', '3 : 2', false, 'Used only the duration ratio (12:8 = 3:2) ignoring the investment amounts. Both dimensions must be multiplied.', 'Duration ratio (12:8 = 3:2) ही लगाया — investments छोड़ दिए। दोनों dimensions multiply करने होते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '4 : 3', '4 : 3', false, 'Used 10×12:15×8 = 120:120 but then arbitrarily added (10+15):(12+8) = 25:20 = 5:4 or similar sum-based garbled ratio.', '10×12:15×8 = 120:120 सही निकाला पर (10+15):(12+8) जैसा sum-based garble कर दिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 21, 'A vessel contains a mixture of milk and water in the ratio 3 : 2. If 4 litres of water are added, the ratio becomes 3 : 4. Find the quantity of milk in the original mixture.', 'एक बर्तन में दूध और पानी का ratio 3 : 2 है। 4 litres पानी मिलाने पर ratio 3 : 4 हो जाता है। मूल mixture में दूध कितना था?', 'Let milk = 3k, water = 2k. After adding 4L water: milk stays 3k, water = 2k + 4. New ratio: 3k/(2k + 4) = 3/4 ⇒ 4 × 3k = 3 × (2k + 4) ⇒ 12k = 6k + 12 ⇒ k = 2. Milk = 3 × 2 = 6 L.', 'Adding pure water changes the water component but leaves the milk component unchanged. Parametrize by k, fix the milk quantity, update the water quantity with the added 4L, and set up the new ratio. Solve the linear equation for k.', 'Milk = 3k, water = 2k मानें। 4L पानी जोड़ने पर milk वही, water = 2k + 4। नई ratio: 3k/(2k + 4) = 3/4 ⇒ 12k = 6k + 12 ⇒ k = 2। Milk = 6 L।', 'Pure पानी जोड़ने पर water बदलता है, milk नहीं। k से parametrize करें, milk fix रखें, water में 4 जोड़ें, नई ratio set करें, k solve करें।', 'MEDIUM', array['ratio-proportion','mixture','water-addition','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '6 litres', '6 litres', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '4 litres', '4 litres', false, 'Reported the water added (4 litres) as the milk quantity. The water addition is separate from the original milk.', 'जोड़े गए पानी (4 litres) को ही milk quantity मान लिया। Addition original milk से अलग है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '8 litres', '8 litres', false, 'Used (final water part) × scale: 4k where k = 2; got 8. Actual: milk doesn''t change, so solve 3k/(2k + 4) = 3/4 directly.', '(4k, k = 2) लगाकर 8 निकाला। सही: milk नहीं बदलता, 3k/(2k + 4) = 3/4 सीधे हल करें।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '12 litres', '12 litres', false, 'Applied k to milk incorrectly: reported 3k as 12 with k = 4. The equation yields k = 2, so milk = 3k = 6.', 'k = 4 लगाकर 3k = 12 दे दिया। सही k = 2, milk = 3k = 6।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 22, 'If a : b = 2 : 3 and b : c = 4 : 5, find a : b : c in its simplest form.', 'यदि a : b = 2 : 3 और b : c = 4 : 5 हो, तो a : b : c सरलतम रूप में क्या है?', 'LCM of b-parts (3 and 4) = 12. Scale first ratio by 4: a:b = 2:3 → 8:12. Scale second ratio by 3: b:c = 4:5 → 12:15. Combined: a:b:c = 8:12:15.', 'Chaining ratios requires matching the shared term exactly. Find the LCM of the two b-values, scale each ratio to that common b, then read off a:b:c directly. LCM scaling guarantees integer parts throughout.', 'b-parts (3 और 4) का LCM = 12। पहली ratio × 4: 2:3 → 8:12। दूसरी ratio × 3: 4:5 → 12:15। मिलाकर a:b:c = 8:12:15।', 'Ratios chain करने के लिए shared term exactly match होना चाहिए। दोनों b-values का LCM निकालकर हर ratio को scale करें, फिर a:b:c पढ़ लें।', 'MEDIUM', array['ratio-proportion','chained-ratio','lcm','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '8 : 12 : 15', '8 : 12 : 15', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '2 : 3 : 5', '2 : 3 : 5', false, 'Concatenated the two ratios without unifying b: kept a''s b-part as 3 but b''s c-part as 5 with b-part 4 — inconsistent b.', 'दोनों ratios को सीधे जोड़ दिया बिना b को unify किए — b-parts 3 और 4 अलग रहे।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '2 : 7 : 5', '2 : 7 : 5', false, 'Added the two b-parts (3 + 4 = 7) to ''reconcile'' them. Correct way: scale to common LCM of 3 and 4 (= 12).', 'दोनों b-parts जोड़कर (3 + 4 = 7) ''reconcile'' करने की कोशिश। सही: 3 और 4 के LCM (= 12) पर scale।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '6 : 12 : 15', '6 : 12 : 15', false, 'Scaled the first ratio by 2 (6:6 — wrong) instead of by 4 (8:12) to make b = 12 common.', 'पहली ratio को 2 से scale किया (6:6 — गलत), 4 से करना था (8:12) ताकि b = 12 common हो।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 23, 'A bag contains 1-rupee, 50-paise, and 25-paise coins in the ratio 2 : 3 : 4. If the total value is ₹45, find the number of 50-paise coins.', 'एक बैग में 1 रुपये, 50 पैसे, और 25 पैसे के सिक्कों का ratio 2 : 3 : 4 है। कुल value ₹45 है। 50 पैसे के कितने सिक्के हैं?', 'Let counts be 2k, 3k, 4k. Total value (in ₹) = 2k × 1 + 3k × 0.5 + 4k × 0.25 = 2k + 1.5k + k = 4.5k. Set 4.5k = 45 ⇒ k = 10. 50-paise count = 3k = 30.', 'When coins of different denominations are in a COUNT-ratio, the VALUE ratio differs. Compute value = count × denomination for each type, sum to get total value, then solve for the scale factor k. Mixing value with count directly gives wrong answers because a 1-rupee coin contributes more to value than a 25-paise coin per unit count.', 'Counts = 2k, 3k, 4k मानें। Total value = 2k × 1 + 3k × 0.5 + 4k × 0.25 = 4.5k = 45 ⇒ k = 10। 50-paise count = 3k = 30।', 'अलग denominations वाले coins की COUNT-ratio में VALUE-ratio अलग होती है। Value = count × denomination हर type के लिए, sum करके total से k निकालें।', 'HARD', array['ratio-proportion','coins','value-vs-count','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '30', '30', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '20', '20', false, 'Reported count of ₹1 coins (2k = 20 with k = 10) as the 50-paise count. 50-paise is the 3-part, not the 2-part.', '₹1 सिक्कों की count (2k = 20, k = 10) को 50-paise count दे दिया। 50-paise 3-part है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '40', '40', false, 'Reported count of 25-paise (4k = 40 with k = 10) as 50-paise. Mistook the 4-part for the 3-part.', '25-paise की count (4k = 40, k = 10) को 50-paise कह दिया। 4-part को 3-part समझा।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '15', '15', false, 'Ignored coin denominations and split the total ₹45 directly in count-ratio 2:3:4: 45 × 3/9 = 15. Each denomination contributes a different amount to the value.', 'Coin denominations छोड़कर ₹45 को सीधे count-ratio 2:3:4 में बाँटा: 45 × 3/9 = 15। हर denomination value में अलग योगदान देता है।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 24, 'In a school, the ratio of boys to girls is 4:3. If 12 more girls join, the ratio becomes 2:3. Find the original number of boys.', 'एक school में लड़कों और लड़कियों का ratio 4:3 है। 12 और लड़कियाँ आ जाएँ तो ratio 2:3 हो जाएगा। मूल लड़कों की संख्या क्या है?', 'Let boys = 4k, girls = 3k. After 12 more girls: 4k/(3k + 12) = 2/3 ⇒ 3 × 4k = 2(3k + 12) ⇒ 12k = 6k + 24 ⇒ 6k = 24 ⇒ k = 4. Boys = 4k = 16.', 'When a ratio shifts because only ONE side changes (e.g., girls increase, boys constant), set up an equation where the unchanged side uses the original k-multiplied value and the changed side adds the delta. Cross-multiply, solve linearly for k, then back-substitute.', 'Boys = 4k, girls = 3k मानें। 12 लड़कियाँ जोड़ने पर 4k/(3k + 12) = 2/3 ⇒ 12k = 6k + 24 ⇒ k = 4। Boys = 4k = 16।', 'सिर्फ एक side बदले तो unchanged side k × original, changed side पर delta जोड़ें, फिर cross-multiply से linear equation।', 'MEDIUM', array['ratio-proportion','one-side-changes','equation-setup','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '16', '16', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '12', '12', false, 'Reported original girls count (3k = 12 with k = 4) as boys. Boys are the 4-part: 4k = 16.', 'मूल girls count (3k = 12, k = 4) को boys कह दिया। Boys 4-part हैं: 4k = 16।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '24', '24', false, 'Computed girls AFTER joining (3k + 12 = 24 with k = 4) and reported as boys. Question asks original boys, not after-shift girls.', 'Girls के 12 जोड़ने के बाद (3k + 12 = 24, k = 4) को boys दे दिया। Question original boys पूछ रहा है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '8', '8', false, 'Used wrong scale k = 2 (instead of 4): 4k = 8. Cross-mult 3(4k) = 2(3k + 12) gives 12k = 6k + 24 ⇒ k = 4, not 2.', 'गलत scale k = 2 (4 की जगह) से 4k = 8 दे दिया। Cross-mult से k = 4।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 25, 'The incomes of A and B are in the ratio 5:4 and their expenditures in the ratio 3:2. If each saves ₹1,000 per month, find A''s monthly income.', 'A और B की incomes का ratio 5:4 और expenditures का ratio 3:2 है। हर कोई ₹1,000 per month बचाता है। A की monthly income क्या है?', 'Let incomes be 5k, 4k and expenditures 3m, 2m. Savings: 5k − 3m = 1000 and 4k − 2m = 1000. Solve: from eq2, 2k = m + 500 ⇒ m = 2k − 500. Substitute: 5k − 3(2k − 500) = 1000 ⇒ 5k − 6k + 1500 = 1000 ⇒ −k = −500 ⇒ k = 500. A''s income = 5k = 2500.', 'Two independent ratios (one for income, one for expenditure) each get their own scale factor. The savings constraint (same for both) gives two equations in two unknowns (k, m). Solve the linear system simultaneously.', 'Incomes = 5k, 4k और expenditures = 3m, 2m मानें। Savings: 5k − 3m = 1000, 4k − 2m = 1000। Solve: k = 500, m = 500। A की income = 5k = 2500।', 'Income और expenditure की स्वतंत्र ratios के अलग scales (k, m)। Savings constraint दोनों के लिए same, अतः दो equations दो variables में।', 'HARD', array['ratio-proportion','income-expenditure','two-ratios','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹2,500', '₹2,500', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹2,000', '₹2,000', false, 'Gave B''s income (4k = 2000 with k = 500) as A''s. A is the 5-part with larger income.', 'B की income (4k = 2000, k = 500) A को दे दी। A 5-part है, बड़ी income।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹1,500', '₹1,500', false, 'Reported A''s expenditure (3m = 1500 with m = 500) as income. Savings = income − expenditure.', 'A की expenditure (3m = 1500, m = 500) को income कह दिया। Savings = income − expenditure।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹5,000', '₹5,000', false, 'Used wrong scale: k = 1000 gives A = 5k = 5000. The two scale factors (k for income, m for expenditure) must both be solved from the savings condition.', 'गलत scale: k = 1000 से A = 5k = 5000। Income और expenditure के दो scales (k, m) दोनों savings condition से solve होने चाहिए।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 26, 'If x : y = 3 : 4 and y : z = 2 : 7, find the value of (x + y) : (y + z).', 'यदि x : y = 3 : 4 और y : z = 2 : 7 हो, तो (x + y) : (y + z) का मान क्या है?', 'Make y common. x:y = 3:4 and y:z = 2:7 = 4:14 (× 2). So x:y:z = 3:4:14. Then (x+y)/(y+z) = (3+4)/(4+14) = 7/18.', 'Whenever a problem combines two ratios into a single expression, first unify the shared term via LCM, then form the chained x:y:z. All subsequent calculations on that triple are straightforward arithmetic on the same scale.', 'y को common बनाएँ। x:y = 3:4 और y:z = 2:7 = 4:14 (× 2)। अतः x:y:z = 3:4:14। (x+y)/(y+z) = 7/18।', 'दो ratios को combine करना हो तो पहले shared term LCM से unify करें, फिर x:y:z बनाएँ। उस triple पर अगली calculations plain arithmetic हैं।', 'HARD', array['ratio-proportion','chained-ratio','combined-expressions','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '7 : 18', '7 : 18', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '5 : 9', '5 : 9', false, 'Used first ratio x+y = 3+4 = 7 and second y+z = 2+7 = 9 without unifying y-value (4 ≠ 2).', 'x+y = 3+4 = 7 और y+z = 2+7 = 9 सीधे लिए बिना y को unify किए (4 ≠ 2)।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '7 : 14', '7 : 14', false, 'Scaled second ratio but only c-part: y:z → 2:7, used y+z = 2+14 but kept y=2. Correct: LCM y → 4 means z → 14 ⇒ y+z = 4+14 = 18.', 'दूसरी ratio में सिर्फ c-part को scale किया। LCM y = 4 से z = 14 → y+z = 4+14 = 18।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '3 : 11', '3 : 11', false, 'Used x=3 (without pairing with y=4): mis-wrote x+y as 3 instead of 3+4=7. Then y+z as 4+7=11 kept one y from wrong side.', 'x+y = 3 लिखा (केवल x); y+z = 4+7 = 11 में y गलत side से लिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 27, 'A sum of money is divided among A, B, C in such a way that for every ₹1 A gets, B gets ₹2 and C gets ₹1.50. If C''s share is ₹450, find the total sum.', 'एक राशि A, B, C में इस तरह बाँटी गई कि A को ₹1 मिलने पर B को ₹2 और C को ₹1.50 मिलता है। C का share ₹450 है। कुल राशि क्या है?', 'Ratio A:B:C = 1:2:1.5 = 2:4:3 (multiplied by 2 to clear decimals). C = 450 corresponds to 3 parts, so 1 part = 150. Total parts = 2+4+3 = 9. Total sum = 9 × 150 = 1350.', 'Decimal ratios behave identically to integer ratios; multiplying all terms by the same factor clears decimals without changing the ratio. Always convert to the cleanest integer form to avoid arithmetic slips.', 'Ratio A:B:C = 1:2:1.5 = 2:4:3 (× 2 से decimal clear)। C = 450 is 3 parts ⇒ 1 part = 150। Total parts = 9 ⇒ Total = 9 × 150 = 1350।', 'Decimal ratios integer ratios जैसे ही काम करती हैं। सभी terms को same factor से × करके decimals clear कर लें।', 'MEDIUM', array['ratio-proportion','partition','decimal-ratio','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '₹1,350', '₹1,350', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '₹900', '₹900', false, 'Summed only A + B (300 + 600 = 900) and forgot to add C''s 450.', 'केवल A + B (300 + 600 = 900) जोड़ा, C का 450 भूल गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '₹1,500', '₹1,500', false, 'Truncated 1.5 to 1 (treated decimal as integer): used ratio 1:2:1, sum = 4, total = 450/1 × 4 = 1800, then subtracted 300 ''for the half''. Correct: 450/1.5 × (1+2+1.5) = 300 × 4.5 = 1350.', '1.5 को 1 truncate कर दिया: ratio 1:2:1, sum = 4, total = 450 × 4 = 1800 निकालकर 300 घटाया। सही: 450/1.5 × (1+2+1.5) = 300 × 4.5 = 1350।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '₹300', '₹300', false, 'Reported A''s share (C/1.5 = 300) as the total. Total spans A + B + C.', 'A का share (C/1.5 = 300) को कुल राशि कह दिया। Total = A + B + C।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 28, 'If 12 men can do a piece of work in 18 days, how many men are needed to complete the same work in 9 days?', 'यदि 12 men किसी काम को 18 दिन में करते हैं, तो वही काम 9 दिन में पूरा करने के लिए कितने men चाहिए?', 'Men × Days = constant (work done). 12 × 18 = M × 9 ⇒ M = 216/9 = 24.', 'In work-time problems, (workers) × (time) = total person-days required for the job. Halving the time requires doubling the workforce. Inverse proportion means one goes up as the other goes down, with the product constant.', 'Men × Days = constant (total work)। 12 × 18 = M × 9 ⇒ M = 216/9 = 24।', 'Work-time में (workers) × (time) = total person-days। Time आधा → men दोगुने। Inverse proportion: एक बढ़े तो दूसरा घटे, product constant।', 'MEDIUM', array['ratio-proportion','inverse-proportion','work-time','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '24', '24', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '6', '6', false, 'Used direct proportion: halved days → halved men (12/2 = 6). Work-time is INVERSELY proportional: fewer days need MORE men.', 'Direct proportion लगाई: days आधे → men आधे (12/2 = 6)। Work-time inverse हैं: कम दिन = ज़्यादा men।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '18', '18', false, 'Swapped the numbers without applying the ratio: used 18 (days) as the answer.', '18 (days) को ही answer लिख दिया — ratio apply नहीं की।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '36', '36', false, 'Multiplied by 3 incorrectly: 12 × 3 = 36. The time ratio is 18/9 = 2, so men scale by 2, not 3.', '× 3 लगाया: 12 × 3 = 36। Time ratio 18/9 = 2 है, अतः men × 2।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 29, 'The ratio of the ages of a man and his wife is 4 : 3. After 4 years, the ratio will be 9 : 7. How old is the wife now?', 'एक पुरुष और उसकी पत्नी की ages का ratio 4 : 3 है। 4 साल बाद यह 9 : 7 हो जाएगा। पत्नी की वर्तमान age क्या है?', 'Let man = 4k, wife = 3k. After 4 years: (4k + 4)/(3k + 4) = 9/7 ⇒ 7(4k + 4) = 9(3k + 4) ⇒ 28k + 28 = 27k + 36 ⇒ k = 8. Wife = 3 × 8 = 24.', 'Spouse ages work exactly like any two-age problem: parametrize both by k, apply the future-ratio constraint, solve for k, return the requested age (wife = 3k here).', 'Man = 4k, wife = 3k मानें। 4 साल बाद (4k + 4)/(3k + 4) = 9/7 ⇒ 7(4k + 4) = 9(3k + 4) ⇒ k = 8। Wife = 3 × 8 = 24।', 'Spouse ages भी दो-age problem जैसा: k से parametrize, future-ratio constraint, k निकालकर requested age।', 'MEDIUM', array['ratio-proportion','age-problem','spouse-ages','cbt1-full-mock','mathematics']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', '24 years', '24 साल', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', '28 years', '28 साल', false, 'Added 4 to the correct answer 24 (returned wife''s age after 4 years instead of now).', 'सही answer 24 में 4 जोड़ दिया (4 साल बाद की age दे दी)।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', '32 years', '32 साल', false, 'Gave husband''s present age (4k = 32, k = 8) as wife''s.', 'पति की present age (4k = 32, k = 8) को पत्नी की दे दी।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', '36 years', '36 साल', false, 'Added 4 to husband''s age (32 + 4 = 36) — doubled the confusion by swapping person AND adding time.', 'पति की age में 4 जोड़कर (32 + 4 = 36) — person और time दोनों गलत।');
insert into public.test_sections (test_id, title_en, title_hi, question_count, display_order, subject_hint) values (v_t, 'General Intelligence & Reasoning', 'General Intelligence & Reasoning', 30, 3, 'reason') returning id into v_s;
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 0, 'If today is Thursday, what day will it be after 52 days?', 'यदि आज Thursday है, तो 52 days बाद कौन सा day होगा?', '52 mod 7 = 3. Move 3 days from Thursday; the day is Sunday. Therefore, answer = Sunday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Sunday.', '52 mod 7 = 3। Thursday से 3 days आगे बढ़ें; day Sunday होगा। अतः answer = Sunday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Sunday है।', 'EASY', array['calendar','odd-days','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Monday', 'Monday', false, 'Counted today as day 1 and shifted one extra day. After 52 days means add 52 mod 7.', 'आज को day 1 count करके एक extra day shift कर दिया। 52 days बाद का मतलब 52 mod 7 add करना है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Sunday', 'Sunday', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Tuesday', 'Tuesday', false, 'Reduced 52 by 7 incorrectly and moved two days too far.', '52 को 7 से गलत reduce किया और two days आगे चले गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Thursday', 'Thursday', false, 'Assumed the same day repeats without checking 52 mod 7. Same day occurs only if remainder is 0.', '52 mod 7 check किए बिना same day मान लिया। Same day तभी होगा जब remainder 0 हो।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 1, 'If today is Saturday, what day will it be after 73 days?', 'यदि आज Saturday है, तो 73 days बाद कौन सा day होगा?', '73 mod 7 = 3. Move 3 days from Saturday; the day is Tuesday. Therefore, answer = Tuesday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Tuesday.', '73 mod 7 = 3। Saturday से 3 days आगे बढ़ें; day Tuesday होगा। अतः answer = Tuesday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Tuesday है।', 'EASY', array['calendar','odd-days','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Wednesday', 'Wednesday', false, 'Counted today as day 1 and shifted one extra day. After 73 days means add 73 mod 7.', 'आज को day 1 count करके एक extra day shift कर दिया। 73 days बाद का मतलब 73 mod 7 add करना है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Thursday', 'Thursday', false, 'Reduced 73 by 7 incorrectly and moved two days too far.', '73 को 7 से गलत reduce किया और two days आगे चले गए।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Tuesday', 'Tuesday', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Saturday', 'Saturday', false, 'Assumed the same day repeats without checking 73 mod 7. Same day occurs only if remainder is 0.', '73 mod 7 check किए बिना same day मान लिया। Same day तभी होगा जब remainder 0 हो।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 2, 'If today is Monday, what day will it be after 87 days?', 'यदि आज Monday है, तो 87 days बाद कौन सा day होगा?', '87 mod 7 = 3. Move 3 days from Monday; the day is Thursday. Therefore, answer = Thursday.', 'Calendar days repeat every 7 days. The remainder on division by 7 gives the effective shift from the starting day. Final answer is Thursday.', '87 mod 7 = 3। Monday से 3 days आगे बढ़ें; day Thursday होगा। अतः answer = Thursday।', 'Calendar days हर 7 days में repeat होते हैं। 7 से remainder effective shift बताता है। Final answer Thursday है।', 'EASY', array['calendar','odd-days','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Friday', 'Friday', false, 'Counted today as day 1 and shifted one extra day. After 87 days means add 87 mod 7.', 'आज को day 1 count करके एक extra day shift कर दिया। 87 days बाद का मतलब 87 mod 7 add करना है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Saturday', 'Saturday', false, 'Reduced 87 by 7 incorrectly and moved two days too far.', '87 को 7 से गलत reduce किया और two days आगे चले गए।');
