insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Thursday', 'Thursday', true, null, null);
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 3, 'Is 2024 a leap year?', 'क्या 2024 leap year है?', '2024 is not a century year, so check divisibility by 4: remainder 0. Result: Leap year. Therefore, answer = Leap year.', 'In the Gregorian calendar, leap years are divisible by 4, but century years must be divisible by 400. This exception removes three leap days every 400 years. Final answer is Leap year.', '2024 century year नहीं है, इसलिए 4 से divisibility check करें: remainder 0. Result: Leap year. अतः answer = Leap year।', 'Gregorian calendar में leap year 4 से divisible होता है, लेकिन century year को 400 से divisible होना चाहिए। Final answer Leap year है।', 'MEDIUM', array['calendar','leap-year','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Leap year', 'Leap year', true, null, null);
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Not a leap year', 'Not a leap year', false, 'Ignored the century rule. Century years must be divisible by 400; other years divisible by 4 are leap years.', 'Century rule ignore किया। Century years 400 से divisible होने चाहिए; बाकी 4 से divisible years leap होते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'C', 'Cannot be decided', 'Cannot be decided', false, 'Treated a standard Gregorian leap-year rule as missing data. The year alone is sufficient.', 'Gregorian leap-year rule के लिए extra data माँगा। Year alone sufficient है।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'D', 'Only if February has 29 days in the given calendar', 'Only if February has 29 days in the given calendar', false, 'Restated the consequence instead of applying the divisibility rule.', 'Rule apply करने की जगह consequence बोल दिया।');
insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 4, 'Is 1900 a leap year?', 'क्या 1900 leap year है?', '1900 is a century year, so check divisibility by 400: remainder 300. Result: Not a leap year. Therefore, answer = Not a leap year.', 'In the Gregorian calendar, leap years are divisible by 4, but century years must be divisible by 400. This exception removes three leap days every 400 years. Final answer is Not a leap year.', '1900 century year है, इसलिए 400 से divisibility check करें: remainder 300. Result: Not a leap year. अतः answer = Not a leap year।', 'Gregorian calendar में leap year 4 से divisible होता है, लेकिन century year को 400 से divisible होना चाहिए। Final answer Not a leap year है।', 'MEDIUM', array['calendar','leap-year','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Leap year', 'Leap year', false, 'Ignored the century rule. Century years must be divisible by 400; other years divisible by 4 are leap years.', 'Century rule ignore किया। Century years 400 से divisible होने चाहिए; बाकी 4 से divisible years leap होते हैं।');
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'B', 'Not a leap year', 'Not a leap year', true, null, null);
