insert into public.questions (section_id, display_order, stem_en, stem_hi, explanation_method_en, explanation_concept_en, explanation_method_hi, explanation_concept_hi, difficulty, tags, source, license, status) values (v_s, 5, 'Is 2000 a leap year?', 'क्या 2000 leap year है?', '2000 is a century year, so check divisibility by 400: remainder 0. Result: Leap year. Therefore, answer = Leap year.', 'In the Gregorian calendar, leap years are divisible by 4, but century years must be divisible by 400. This exception removes three leap days every 400 years. Final answer is Leap year.', '2000 century year है, इसलिए 400 से divisibility check करें: remainder 0. Result: Leap year. अतः answer = Leap year।', 'Gregorian calendar में leap year 4 से divisible होता है, लेकिन century year को 400 से divisible होना चाहिए। Final answer Leap year है।', 'MEDIUM', array['calendar','leap-year','cbt1-full-mock','reasoning']::text[], 'Original', 'ORIGINAL', 'active') returning id into v_q;
insert into public.options (question_id, label, text_en, text_hi, is_correct, trap_reason_en, trap_reason_hi) values (v_q, 'A', 'Not a leap year', 'Not a leap year', false, 'Ignored the century rule. Century years must be divisible by 400; other years divisible by 4 are leap years.', 'Century rule ignore किया। Century years 400 से divisible होने चाहिए; बाकी 4 से divisible years leap होते हैं।');
